def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        score = 0.0
        residual = capacity - item
        decay_rate = 0.8
        weight = 2.0
        bonus_factor = 1.0
        for depth in range(1, 8):
            if residual <= 0:
                score += (25 / depth**1.5) * np.exp(-depth/4)
            else:
                score += ((weight / residual) * (depth ** 1.3)) / (1 + depth * 0.1)
            residual *= decay_rate
            if depth % 3 == 0:
                weight *= 0.85
                bonus_factor *= 1.05
            else:
                weight *= 1.1
        if capacity > 5 * item:
            score *= 0.7
            bonus_factor *= 0.9
        elif capacity > 4 * item:
            score *= 0.8
            bonus_factor *= 0.95
        elif capacity > 2 * item:
            score *= 1.1
            bonus_factor *= 1.2
        elif capacity > item:
            score *= 1.3
            bonus_factor *= 1.3
        else:
            score *= 1.5
            bonus_factor *= 1.5
        penalty = 0.0
        for check1 in range(1, int(np.ceil(item)) + 4):
            for check2 in range(1, int(np.ceil(capacity / 2)) + 2):
                mod_val = (capacity - check1 * check2) % (check1 + check2)
                if mod_val == 0:
                    penalty -= 0.4 * ((check1 + check2) ** 1.2)
                elif mod_val % 3 == 0:
                    penalty += 0.25 * ((check1 * check2) ** 0.8)
                else:
                    penalty -= 0.1 * ((check1 - check2) ** 1.1) if (check1 > check2) else 0.1 * ((check2 - check1) ** 1.1)
        score += penalty * bonus_factor
        if score < 0:
            priorities[i] = 0
        elif score > 250:
            priorities[i] = 250
        else:
            priorities[i] = score
        if abs(capacity - item) < 0.1 * item:
            priorities[i] *= 1.15
        elif abs(capacity - item) > 0.9 * capacity:
            priorities[i] *= 0.9
        if priorities[i] != np.inf:
            finescale = 0
            for mod_check in range(1, 5):
                mod_val = capacity % (mod_check + 1)
                if mod_val == 0:
                    finescale += 0.1 * mod_check
                elif mod_val == 1:
                    finescale -= 0.05 * mod_check
            priorities[i] += finescale
    return priorities
